scwin.f_empNo = async function () {
  console.log("=== f_empNo (증빙관리권한 조회 - 세무조사id 여부)");

  // 데이타셋 초기화 필요
  ds_empNo.removeAll();
  var grp_cd = "FI624"; // FI624 (증빙관리권한)
  //	var pCode = '<%=empNo%>' ;
  var pCode = scwin.empNo;

  // SELECT 절 
  var param1 = "CD  as COL1 , CD_NM  as COL2 , ''  as COL3 , ''  as COL4 , ''  as COL5 , ''  as COL6 , ''  as COL7 , ''  as COL8 , ''  as COL9 , ''  as COL10";

  // 대상테이블 	
  var param2 = " TB_ZZ002 ";

  // 조건절
  var param3 = " AND GRP_CD = '" + grp_cd + "' AND USE_YN = '1' AND CD_NM = '" + pCode + "' ";
  var param4 = "CD";

  //	ds_empNo.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
  //	ds_empNo.Reset();

  // FI624 (증빙관리권한) - 01: user01, 02: user31, 03: user32, 04: user33, 05: user34, 06: user35, 07: user36, 08: user37
  // 2025-10-02 : 세무조사시에만 사용하는 계정으로 , 세무조사 인원이 조회시 보이지 않아야 하는 부분으로 구현 필요

  const strParam = {
    sysCd: "CommonEBC" // 시스템코드
    ,

    queryId: "dinymicQueryTest" // 쿼리ID
    ,

    param1: param1 // SELECT
    ,

    param2: param2 // 대상테이블
    ,

    param3: param3 // 조건절
    ,

    param4: param4 // CD
  };

  //데이터셋에 정보설정
  ds_commonCode.setJSON(strParam);
  let e = await $c.sbm.execute($p, sbm_searchCommon);
  console.log("▷ sbm_searchCommon_submitdone (증빙관리권한 - 세무조사용id 조회 submitdone)");

  // 2025-10-02 : 세무조사시에만 사용하는 계정으로 , 세무조사 인원이 조회시 보이지 않아야 하는 부분으로 구현 필요
  // language=JavaScript for=ds_empNo event=OnLoadCompleted(rowCnt)>

  if (e.responseJSON.resultDataSet[0].Code != 0) return;
  if (e.responseJSON.GAUCE) {
    ds_empNo.setJSON(e.responseJSON.GAUCE);
  }
  var empCnt = ds_empNo.getTotalRow();
  console.log("==== empCnt (세무조사용id 건수 - FI624) : " + empCnt);

  // <!-- 세무조사 아이디 로그인시  셋팅 -->
  // language=JavaScript for=ds_empNo event=OnLoadCompleted(rowCnt)>
  // 	if (ds_empNo.CountRow > 0) {
  // 		console.log("------ 세무조사 > 0 ----");

  // 		ed_slipDtEnd.text ="20150131"; //작성일자 셋팅
  // 		ed_slipDtSt.text = "20150101";

  // 		ed_slipKndCd.style.visibility = "hidden"
  // 		slipKndGb.style.visibility = "hidden"
  // 		txt_slipKndNm.style.visibility = "hidden"
  // 		img_slipKndCd.style.visibility = "hidden"

  // 		gr_mgntPrfloss.ColumnProp("drawEmpNm",	"Show") = "false";  // 작성자
  // 		gr_mgntPrfloss.ColumnProp("slipKndNm",	"Show") = "false";  // 전표종류명

  // 	}else{
  // 		System.out.println("------ 세무조사 <= 0 ----");

  // 		ed_slipKndCd.style.visibility ="visible"
  // 		slipKndGb.style.visibility ="visible"
  // 		txt_slipKndNm.style.visibility ="visible"
  // 		img_slipKndCd.style.visibility ="visible"

  // 		gr_mgntPrfloss.ColumnProp("drawEmpNm",	"Show") = "true";  // 작성자
  // 		gr_mgntPrfloss.ColumnProp("slipKndNm",	"Show") = "true";  // 전표종류명
  // 	}

  // KYU_TEST (세무조사 로그인 환경)
  //empCnt = 1;

  if (empCnt > 0) {
    console.log("---- 세무조사 사용자 로그인 : ----------------");
    udc_slipDt.ed_slipDtEnd = "20150131"; //작성일자 셋팅
    udc_slipDt.ed_slipDtSt = "20150101";

    // 전표종류 table hide
    vSlipKind.hide();

    //gr_mgntPrfloss.ColumnProp("drawEmpNm",	"Show") = "false";  // 작성자
    //gr_mgntPrfloss.ColumnProp("slipKndNm",	"Show") = "false";  // 전표종류명

    gr_mgntPrfloss.setColumnVisible("drawEmpNm", "false"); // 작성자
    gr_mgntPrfloss.setColumnVisible("slipKndNm", "false"); // 전표종류명
  } else {
    console.log("---- 일반 사용자 로그인 : ----------------");

    // 전표종류 table show
    vSlipKind.show("");

    //gr_mgntPrfloss.ColumnProp("drawEmpNm",	"Show") = "true";
    //gr_mgntPrfloss.ColumnProp("slipKndNm",	"Show") = "true";

    gr_mgntPrfloss.setColumnVisible("drawEmpNm", "true"); // 작성자
    gr_mgntPrfloss.setColumnVisible("slipKndNm", "true"); // 전표종류명
  }
};

