scwin.f_PostYn = function () {
  if (lc_postYn.getValue() == "1") {
    // 결제
    console.log("  --- 결제 선택");

    // cfEnableObjects([ed_postDtSt, ed_postDtEnd])
    // cfDisableObjects([ed_slipDtSt, ed_slipDtEnd])
    // ed_slipDtSt.text = "" ;
    // ed_slipDtEnd.text = "" ;
    // ed_postDtSt.focus();
    $c.gus.cfEnableObjects($p, [ed_postDtSt, ed_postDtEnd]); // 회계일자
    $c.gus.cfDisableObjects($p, [ed_slipDtSt, ed_slipDtEnd]); // 작성일자
    ed_slipDtSt.setValue("");
    ed_slipDtEnd.setValue("");
    ed_postDtSt.focus();
  } else if (lc_postYn.getValue() == "0") {
    // 가결
    // cfDisableObjects([ed_postDtSt, ed_postDtEnd])
    // cfEnableObjects([ed_slipDtSt, ed_slipDtEnd])
    // ed_postDtSt.text = "" ;
    // ed_postDtEnd.text = "" ;
    // ed_slipDtSt.focus();

    $c.gus.cfDisableObjects($p, [ed_postDtSt, ed_postDtEnd]); // 회계일자
    $c.gus.cfEnableObjects($p, [ed_slipDtSt, ed_slipDtEnd]); // 작성일자
    ed_postDtSt.setValue("");
    ed_postDtEnd.setValue("");
    ed_slipDtSt.focus();
  } else if (lc_postYn.getValue() == "") {
    // 전체
    console.log("  --- 전체 선택 : null");
    // cfEnableObjects([ed_postDtSt, ed_postDtEnd])
    // cfEnableObjects([ed_slipDtSt, ed_slipDtEnd])
    // ed_slipDtSt.focus();

    $c.gus.cfEnableObjects($p, [ed_postDtSt, ed_postDtEnd]); // 회계일자
    $c.gus.cfEnableObjects($p, [ed_slipDtSt, ed_slipDtEnd]); // 작성일자
    ed_slipDtSt.focus();
  }
};

